# Agent stop-action controller: halt and queue agentic operations

from dataclasses import dataclass, field
from datetime import datetime
from typing import Literal, Callable, Any
import threading

ActionStatus = Literal["queued","executing","completed","halted","rolled_back"]

@dataclass
class AgentAction:
    action_id: str
    agent_id: str
    action_type: str
    payload: dict
    created_at: datetime
    status: ActionStatus = "queued"
    executed_at: datetime | None = None
    result: Any = None
    rollback_fn: Callable | None = None

    def rollback(self) -> bool:
        if self.rollback_fn and self.status == "completed":
            self.rollback_fn(self)
            self.status = "rolled_back"
            return True
        return False

class AgentController:
    def __init__(self):
        self._halted = False
        self._queue: list[AgentAction] = []
        self._lock = threading.Lock()

    def halt(self, reason: str) -> dict:
        with self._lock:
            self._halted = True
            halted_count = len([a for a in self._queue if a.status == "queued"])
            return {
                "halted": True,
                "reason": reason,
                "queued_actions_suspended": halted_count,
                "timestamp": datetime.now().isoformat(),
            }

    def resume(self, authorised_by: str) -> dict:
        with self._lock:
            self._halted = False
            return {"resumed": True, "authorised_by": authorised_by, "timestamp": datetime.now().isoformat()}

    def submit_action(self, action: AgentAction) -> dict:
        with self._lock:
            if self._halted:
                action.status = "halted"
                self._queue.append(action)
                return {"accepted": False, "reason": "system_halted", "action_id": action.action_id}
            self._queue.append(action)
            return {"accepted": True, "action_id": action.action_id}

    def rollback_window(self, since: datetime) -> list[str]:
        rolled = []
        for action in self._queue:
            if action.executed_at and action.executed_at >= since:
                if action.rollback():
                    rolled.append(action.action_id)
        return rolled
